	var deprecations []deprecation

	if v.InConfig("tracing.jaeger.enabled") {
		deprecations = append(deprecations, deprecation{
			option:            "tracing.jaeger.enabled",
			additionalMessage: deprecatedMsgTracingJaegerEnabled,
		})
	}

	return deprecations
}

